import{_ as i,c as a,o as t,ae as s}from"./chunks/framework.Bw7rlmih.js";const u=JSON.parse('{"title":"04: Drift Detection","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/04-drift-detection.md","filePath":"control-plane/04-drift-detection.md"}'),l={name:"control-plane/04-drift-detection.md"};function o(n,e,r,d,c,h){return t(),a("div",null,e[0]||(e[0]=[s(`<h1 id="_04-drift-detection" tabindex="-1">04: Drift Detection <a class="header-anchor" href="#_04-drift-detection" aria-label="Permalink to &quot;04: Drift Detection&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Drift detection compares <strong>desired state</strong> (pinned Konfigo bundle and policy) with <strong>actual state</strong> (runtime/config provider values) for a specific scope.</p><p>This feature answers:</p><ul><li>What changed outside approved Konfigo workflows?</li><li>Which differences are dangerous vs informational?</li><li>What is the recommended remediation path?</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>Detect configuration drift continuously and on demand.</li><li>Classify drift by type and severity.</li><li>Emit structured drift events for automation.</li><li>Provide actionable remediation commands and APIs.</li></ul><h2 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-Goals&quot;">​</a></h2><ul><li>Automatic self-healing in initial version.</li><li>Runtime payload enforcement (HTTP/gRPC stream checks).</li><li>Full policy engine redesign.</li></ul><h2 id="drift-types" tabindex="-1">Drift Types <a class="header-anchor" href="#drift-types" aria-label="Permalink to &quot;Drift Types&quot;">​</a></h2><p>Drift result entries must use one of these classes:</p><ul><li><code>missing</code>: expected key/path absent in actual state.</li><li><code>extra</code>: unexpected key/path exists in actual state.</li><li><code>value_mismatch</code>: same key exists but value differs.</li><li><code>schema_violation</code>: actual value no longer conforms to schema.</li><li><code>policy_violation</code>: value exists but violates policy constraints.</li><li><code>stale_version</code>: runtime uses outdated bundle reference.</li></ul><h2 id="scope-model" tabindex="-1">Scope Model <a class="header-anchor" href="#scope-model" aria-label="Permalink to &quot;Scope Model&quot;">​</a></h2><p>Every drift run is bound to a <code>scope</code> prefix:</p><ul><li>Example: <code>platform/payments/prod/api</code></li><li>Vault source path: <code>kv/konfigo/platform/payments/prod/api/...</code></li><li>S3 source path: <code>s3://konfigo-config/platform/payments/prod/api/...</code></li></ul><h2 id="detection-modes" tabindex="-1">Detection Modes <a class="header-anchor" href="#detection-modes" aria-label="Permalink to &quot;Detection Modes&quot;">​</a></h2><h3 id="_1-on-demand-scan" tabindex="-1">1. On-Demand Scan <a class="header-anchor" href="#_1-on-demand-scan" aria-label="Permalink to &quot;1. On-Demand Scan&quot;">​</a></h3><p>Triggered by user/CI:</p><ul><li>CLI: <code>konfigo drift scan --scope platform/payments/prod/api --bundle release-2026-02-25</code></li><li>API: <code>POST /v1/drift/scans</code></li></ul><h3 id="_2-scheduled-scan" tabindex="-1">2. Scheduled Scan <a class="header-anchor" href="#_2-scheduled-scan" aria-label="Permalink to &quot;2. Scheduled Scan&quot;">​</a></h3><p>Configured cadence per scope:</p><ul><li>every 5m, 15m, 1h, etc.</li><li>Optional quiet windows.</li></ul><h3 id="_3-change-triggered-scan" tabindex="-1">3. Change-Triggered Scan <a class="header-anchor" href="#_3-change-triggered-scan" aria-label="Permalink to &quot;3. Change-Triggered Scan&quot;">​</a></h3><p>Triggered by source change signals:</p><ul><li>Consul watch</li><li>etcd watch</li><li>Redis pub/sub signal</li><li>Vault secret version update</li></ul><h2 id="data-inputs" tabindex="-1">Data Inputs <a class="header-anchor" href="#data-inputs" aria-label="Permalink to &quot;Data Inputs&quot;">​</a></h2><p>A scan builds two normalized snapshots:</p><ol><li><strong>Desired snapshot</strong></li></ol><ul><li>Resolved from <code>Bundle@version</code></li><li>Includes schema and policy context</li></ul><ol start="2"><li><strong>Actual snapshot</strong></li></ol><ul><li>Pulled from configured providers</li><li>Includes metadata (version, lease, etag, updatedAt)</li></ul><h2 id="normalization-rules" tabindex="-1">Normalization Rules <a class="header-anchor" href="#normalization-rules" aria-label="Permalink to &quot;Normalization Rules&quot;">​</a></h2><ul><li>Convert all sources to canonical map form.</li><li>Apply deterministic ordering for object keys.</li><li>Normalize number/bool/string format where schema allows.</li><li>Preserve provider metadata separately from value payload.</li></ul><h2 id="detection-algorithm" tabindex="-1">Detection Algorithm <a class="header-anchor" href="#detection-algorithm" aria-label="Permalink to &quot;Detection Algorithm&quot;">​</a></h2><ol><li>Load bundle, schema, policy for scope.</li><li>Resolve desired values to canonical representation.</li><li>Fetch actual values from configured providers.</li><li>Run structural diff (<code>missing</code>, <code>extra</code>, <code>value_mismatch</code>).</li><li>Validate actual against schema and policy.</li><li>Mark stale bundle or stale template/schema refs.</li><li>Assign severity score per finding.</li><li>Persist report and emit events.</li></ol><h2 id="severity-model" tabindex="-1">Severity Model <a class="header-anchor" href="#severity-model" aria-label="Permalink to &quot;Severity Model&quot;">​</a></h2><ul><li><code>critical</code>: policy violation, schema violation on required key.</li><li><code>high</code>: missing required key, stale version in protected scope.</li><li><code>medium</code>: value mismatch on managed key.</li><li><code>low</code>: extra key not on denylist.</li><li><code>info</code>: cosmetic non-impacting differences.</li></ul><h2 id="suppression-and-ignore-rules" tabindex="-1">Suppression and Ignore Rules <a class="header-anchor" href="#suppression-and-ignore-rules" aria-label="Permalink to &quot;Suppression and Ignore Rules&quot;">​</a></h2><p>Support scoped suppressions:</p><ul><li>Temporary suppression (<code>expiresAt</code>).</li><li>Path-based ignore patterns.</li><li>Provider-metadata-only ignore toggles.</li></ul><p>Example ignore rule:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">ignore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">scope</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;platform/payments/prod/api&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;metadata.lastRotated&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    reason</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;managed by external rotator&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    expiresAt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-03-15T00:00:00Z&quot;</span></span></code></pre></div><h2 id="api-contract" tabindex="-1">API Contract <a class="header-anchor" href="#api-contract" aria-label="Permalink to &quot;API Contract&quot;">​</a></h2><h3 id="create-scan" tabindex="-1">Create Scan <a class="header-anchor" href="#create-scan" aria-label="Permalink to &quot;Create Scan&quot;">​</a></h3><p><code>POST /v1/drift/scans</code></p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;scope&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;platform/payments/prod/api&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;bundleRef&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;release-2026-02-25&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;providers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;vault&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;s3&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;on_demand&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="get-scan-result" tabindex="-1">Get Scan Result <a class="header-anchor" href="#get-scan-result" aria-label="Permalink to &quot;Get Scan Result&quot;">​</a></h3><p><code>GET /v1/drift/scans/{scanId}</code></p><p>Response includes:</p><ul><li>summary counts by drift type and severity</li><li>detailed findings</li><li>recommended remediation actions</li></ul><h3 id="list-active-drift" tabindex="-1">List Active Drift <a class="header-anchor" href="#list-active-drift" aria-label="Permalink to &quot;List Active Drift&quot;">​</a></h3><p><code>GET /v1/drift/findings?scope=platform/payments/prod/api&amp;status=open</code></p><h2 id="cli-ux" tabindex="-1">CLI UX <a class="header-anchor" href="#cli-ux" aria-label="Permalink to &quot;CLI UX&quot;">​</a></h2><ul><li><code>konfigo drift scan --scope &lt;scope&gt; --bundle &lt;bundleRef&gt;</code></li><li><code>konfigo drift list --scope &lt;scope&gt;</code></li><li><code>konfigo drift show &lt;scanId&gt;</code></li><li><code>konfigo drift resolve &lt;findingId&gt; --reason &quot;accepted external change&quot;</code></li></ul><h2 id="event-emission" tabindex="-1">Event Emission <a class="header-anchor" href="#event-emission" aria-label="Permalink to &quot;Event Emission&quot;">​</a></h2><p>Emit at least:</p><ul><li><code>drift.scan.started</code></li><li><code>drift.scan.completed</code></li><li><code>drift.finding.opened</code></li><li><code>drift.finding.resolved</code></li></ul><p>Event payload includes <code>scope</code>, <code>bundleRef</code>, <code>findingType</code>, <code>severity</code>, and source metadata.</p><h2 id="remediation-patterns" tabindex="-1">Remediation Patterns <a class="header-anchor" href="#remediation-patterns" aria-label="Permalink to &quot;Remediation Patterns&quot;">​</a></h2><ul><li>Re-apply pinned bundle to target provider.</li><li>Promote updated bundle through approval flow.</li><li>Add justified suppression when external system is authoritative.</li></ul><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li>Scan permissions require read access to scope and provider credentials.</li><li>Findings are access-controlled by scope prefix.</li><li>Sensitive values are redacted in reports, but hash fingerprints are retained.</li></ul><h2 id="metrics" tabindex="-1">Metrics <a class="header-anchor" href="#metrics" aria-label="Permalink to &quot;Metrics&quot;">​</a></h2><ul><li><code>drift_scan_duration_seconds</code></li><li><code>drift_findings_total{type,severity}</code></li><li><code>drift_open_findings</code></li><li><code>drift_time_to_resolution_seconds</code></li></ul><h2 id="rollout-plan" tabindex="-1">Rollout Plan <a class="header-anchor" href="#rollout-plan" aria-label="Permalink to &quot;Rollout Plan&quot;">​</a></h2><h3 id="phase-1" tabindex="-1">Phase 1 <a class="header-anchor" href="#phase-1" aria-label="Permalink to &quot;Phase 1&quot;">​</a></h3><ul><li>On-demand scans for Vault + S3.</li><li>Structural diff only.</li></ul><h3 id="phase-2" tabindex="-1">Phase 2 <a class="header-anchor" href="#phase-2" aria-label="Permalink to &quot;Phase 2&quot;">​</a></h3><ul><li>Scheduled scans and schema/policy drift classes.</li></ul><h3 id="phase-3" tabindex="-1">Phase 3 <a class="header-anchor" href="#phase-3" aria-label="Permalink to &quot;Phase 3&quot;">​</a></h3><ul><li>Source-triggered scans (watch integrations).</li><li>Suppression lifecycle automation.</li></ul><h2 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to &quot;Testing Strategy&quot;">​</a></h2><ul><li>Unit tests for diff classifiers and normalizer.</li><li>Provider integration tests with fixture data.</li><li>End-to-end tests on protected scope with stale version scenarios.</li><li>Load tests for high-cardinality scopes.</li></ul><h2 id="open-decisions" tabindex="-1">Open Decisions <a class="header-anchor" href="#open-decisions" aria-label="Permalink to &quot;Open Decisions&quot;">​</a></h2><ul><li>Maximum supported scan interval granularity.</li><li>Default retention period for scan reports.</li><li>Whether to include optional auto-remediation for low-severity drift in a later version.</li></ul>`,75)]))}const m=i(l,[["render",o]]);export{u as __pageData,m as default};
